+const fn spinner_glyph(phase: u8) -> &'static str {
+    match phase % 8 {
+        0 | 4 => "\u{25d0}",
+        1 | 5 => "\u{25d3}",
+        2 | 6 => "\u{25d1}",
+        _ => "\u{25d2}",
+    }
