+
+fn pulse_meter(phase: u8, width: usize) -> String {
+    const BARS: [char; 8] = [
+        '\u{2581}', '\u{2582}', '\u{2583}', '\u{2584}', '\u{2585}', '\u{2586}', '\u{2587}',
+        '\u{2588}',
+    ];
+    let w = width.max(4);
+    let mut out = String::with_capacity(w);
+    for idx in 0..w {
+        let pos = (usize::from(phase) + idx) % BARS.len();
+        out.push(BARS[pos]);
+    }
+    out
+}
